def make_oracle(secret, N):
    secret_bits = [(secret >> i) & 1 for i in range(N)]
    def f(x):
        x_bits = [(x >> i) & 1 for i in range(N)]
        if N < 2:
            return 0 # Not well-defined for N < 2

        products = []
        for i in range(1, N):
            products.append(x_bits[i] * x_bits[i-1])

        # Compare products with secret bits (relevant parts of secret)
        match_count = 0
        # The secret relevant to products has length N-1
        for i in range(N - 1):
            if products[i] == secret_bits[i+1]: # Comparing product x_i*x_{i-1} with secret bit s_{i+1}
                match_count += 1

        # Majority function on N-1 products
        if match_count > (N - 1) / 2:
            return 1
        else:
            return 0
    return f

